import{_ as a,o,c as t,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-006 — JSON files for mission data","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-006.md","filePath":"adr/ADR-006.md"}'),s={name:"adr/ADR-006.md"};function n(r,e,d,c,l,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-006-—-json-files-for-mission-data" tabindex="-1">ADR-006 — JSON files for mission data <a class="header-anchor" href="#adr-006-—-json-files-for-mission-data" aria-label="Permalink to &quot;ADR-006 — JSON files for mission data&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-04-01 TA anchor · §stack · §contracts/mission-record</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The application needs 28 mission records, 8 planet records, rocket specs, and Earth orbit objects. These could live as JavaScript constants or as separate data files.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Plain JSON files in <code>data/</code>. One file per mission. <code>data/missions/index.json</code> for the lightweight manifest. <code>data/planets.json</code>, <code>data/rockets.json</code>, <code>data/earth-objects.json</code> for reference data.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>A contributor who wants to add a mission or correct a launch date should be able to do so by editing a JSON file. They should not need to understand the JavaScript codebase. A pull request adding a new mission is a diff of two JSON files — reviewable by anyone who knows the domain. This is a design principle (PA §principles: &quot;data over code&quot;) expressed as an architectural decision.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li>JS constants in <code>src/data/*.js</code> — easier to implement initially; couples data to code; requires a developer to update data; original prototype approach, explicitly replaced.</li><li>SQLite / any database — no backend; out of scope for a static deployment.</li><li>CSV files — less expressive than JSON for nested structures (links arrays, events arrays).</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: data is accessible to non-developers; no rebuild needed for data updates (combined with ADR-007); PR review is domain-knowledge review not code review. Negative: <code>fetch()</code> adds latency on first load (mitigated by the cache in <code>data.js</code>); data validation is runtime not compile-time.</p>',12)])])}const f=a(s,[["render",n]]);export{u as __pageData,f as default};
